import{_ as a,o as l,c as t,a2 as i}from"./chunks/framework.CuEaBji2.js";const T=JSON.parse('{"title":"安全最佳实践","description":"","frontmatter":{},"headers":[],"relativePath":"reference/security.md","filePath":"reference/security.md","lastUpdated":1782021666000}'),o={name:"reference/security.md"};function r(d,e,c,n,h,s){return l(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="安全最佳实践" tabindex="-1">安全最佳实践 <a class="header-anchor" href="#安全最佳实践" aria-label="Permalink to &quot;安全最佳实践&quot;">​</a></h1><p>本页汇总了让 nginx-reverse-emby 更安全的关键措施。每一条都值得花几分钟确认。</p><h2 id="密码和令牌" tabindex="-1">密码和令牌 <a class="header-anchor" href="#密码和令牌" aria-label="Permalink to &quot;密码和令牌&quot;">​</a></h2><ul><li><code>API_TOKEN</code> 用 32 位以上随机字符串，包含大小写字母和数字。不要用简单密码。</li><li><code>MASTER_REGISTER_TOKEN</code> 单独设置一个不同的值，不要和 <code>API_TOKEN</code> 共用。</li><li>这两个 Token 都不要提交到 Git 仓库，不要在公开渠道（聊天记录、论坛、截图）中暴露。</li></ul><h2 id="data-目录保护" tabindex="-1">data 目录保护 <a class="header-anchor" href="#data-目录保护" aria-label="Permalink to &quot;data 目录保护&quot;">​</a></h2><p><code>./data</code> 目录包含 SQLite 数据库、证书私钥、Agent Token 等敏感信息：</p><ul><li>不要提交到 Git 仓库（确保 <code>.gitignore</code> 包含 <code>data/</code>）</li><li>不要上传到公共网盘</li><li>备份文件加密后再存储到远程</li></ul><h2 id="面板访问控制" tabindex="-1">面板访问控制 <a class="header-anchor" href="#面板访问控制" aria-label="Permalink to &quot;面板访问控制&quot;">​</a></h2><ul><li>默认 <code>docker-compose.yaml</code> 只监听 <code>127.0.0.1:8080</code>。首次登录建议通过 SSH 隧道访问 <code>http://127.0.0.1:8080</code>。</li><li>面板可以给自己提供 HTTPS：登录后创建 <code>https://panel.example.com -&gt; http://127.0.0.1:8080</code> 的 HTTP 规则，使用 <code>local</code> Agent 自动申请证书并代理回控制面。</li><li>面板自身 HTTPS 可用后，设置 <code>NRE_PUBLIC_URL=https://你的面板域名</code>，让 join script 和 Agent 更新 URL 使用固定可信地址。</li><li>不要把面板 8080 端口直接暴露到公网 HTTP。如果需要公网监听，必须配合防火墙限制来源 IP。</li><li>只有在额外使用上游反代，且上游会清洗并重写 <code>X-Forwarded-*</code> 头时，才设置 <code>NRE_TRUST_FORWARDED_HEADERS=true</code>。</li></ul><h2 id="防火墙" tabindex="-1">防火墙 <a class="header-anchor" href="#防火墙" aria-label="Permalink to &quot;防火墙&quot;">​</a></h2><p>只放行真正需要的端口，不要一把全开：</p><ul><li>面板端口：限制来源 IP</li><li>HTTP 入口：80</li><li>HTTPS 入口：443</li><li>自定义监听端口：按实际规则逐个放行</li></ul><h2 id="证书安全" tabindex="-1">证书安全 <a class="header-anchor" href="#证书安全" aria-label="Permalink to &quot;证书安全&quot;">​</a></h2><ul><li>证书私钥不要复制传播，不要提交到仓库</li><li>Cloudflare API Token 只授予必要权限（区域读取 + DNS 读取/编辑），定期轮换</li><li>详情见 <a href="./../guides/certificates">证书与 HTTPS</a></li></ul><h2 id="agent-注册安全" tabindex="-1">Agent 注册安全 <a class="header-anchor" href="#agent-注册安全" aria-label="Permalink to &quot;Agent 注册安全&quot;">​</a></h2><ul><li><code>MASTER_REGISTER_TOKEN</code> 是 Agent 注册的唯一凭证，泄露后任何人都可以注册 Agent 接入你的控制面</li><li>定期检查 <strong>节点管理</strong> 页面，移除不认识的 Agent</li></ul><h2 id="数据库安全" tabindex="-1">数据库安全 <a class="header-anchor" href="#数据库安全" aria-label="Permalink to &quot;数据库安全&quot;">​</a></h2><ul><li>如果使用 PostgreSQL 或 MySQL，数据库密码独立设置，不要复用其他密码</li><li>数据库端口不要暴露在公网</li></ul><h2 id="及时升级" tabindex="-1">及时升级 <a class="header-anchor" href="#及时升级" aria-label="Permalink to &quot;及时升级&quot;">​</a></h2><p>定期更新控制面和 Agent 到最新版本以获取安全修复。更新前先备份 data 目录，以防万一。</p>',20)])])}const _=a(o,[["render",r]]);export{T as __pageData,_ as default};
